import{_ as e,o,c as a,a2 as i}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Notifications and Webhooks","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/notifications.md","filePath":"en/guide/notifications.md"}'),n={name:"en/guide/notifications.md"};function s(r,t,l,d,c,h){return o(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="notifications-and-webhooks" tabindex="-1">Notifications and Webhooks <a class="header-anchor" href="#notifications-and-webhooks" aria-label="Permalink to &quot;Notifications and Webhooks&quot;">​</a></h1><p>Nid keeps you informed of important events through in-app notifications and webhooks to your favorite services.</p><hr><h2 id="in-app-notifications" tabindex="-1">In-App Notifications <a class="header-anchor" href="#in-app-notifications" aria-label="Permalink to &quot;In-App Notifications&quot;">​</a></h2><h3 id="notification-bell" tabindex="-1">Notification Bell <a class="header-anchor" href="#notification-bell" aria-label="Permalink to &quot;Notification Bell&quot;">​</a></h3><p>The <strong>🔔</strong> icon in the navigation bar displays your notifications. The red badge indicates the number of unread notifications.</p><blockquote><p>📸 <em>Suggested screenshot: notification bell with badge and dropdown panel showing notifications</em></p></blockquote><h3 id="notification-actions" tabindex="-1">Notification Actions <a class="header-anchor" href="#notification-actions" aria-label="Permalink to &quot;Notification Actions&quot;">​</a></h3><ul><li>Click a notification to mark it as read</li><li><strong>Mark all as read</strong>: marks all notifications as read</li><li><strong>Delete</strong>: deletes a notification individually</li><li><strong>Delete read</strong>: deletes all already-read notifications</li></ul><h3 id="notification-types" tabindex="-1">Notification Types <a class="header-anchor" href="#notification-types" aria-label="Permalink to &quot;Notification Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Notification</th><th>Description</th></tr></thead><tbody><tr><td><strong>Weekly report</strong></td><td>Summary of your email activity for the week</td></tr><tr><td><strong>Job completed</strong></td><td>A job (archiving, deletion, etc.) completed successfully</td></tr><tr><td><strong>Job failed</strong></td><td>A job failed after 3 attempts</td></tr><tr><td><strong>Rule executed</strong></td><td>An automatic rule was executed</td></tr><tr><td><strong>Quota alert</strong></td><td>Your storage quota is approaching its limit</td></tr><tr><td><strong>Integrity alert</strong></td><td>The archive integrity check detected an issue</td></tr></tbody></table><hr><h2 id="notification-preferences" tabindex="-1">Notification Preferences <a class="header-anchor" href="#notification-preferences" aria-label="Permalink to &quot;Notification Preferences&quot;">​</a></h2><p>Customize notification channels for each event type.</p><ol><li>Go to <strong>Settings</strong> → <strong>Notification Preferences</strong> section</li><li>For each notification type, enable or disable channels:</li></ol><table tabindex="0"><thead><tr><th>Channel</th><th>Description</th></tr></thead><tbody><tr><td>🔔 <strong>In-app</strong></td><td>Creates a notification in the header bell</td></tr><tr><td>💬 <strong>Toast</strong></td><td>Displays a temporary pop-up at the bottom of the page</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: notification preferences table with in-app and toast toggles for each type</em></p></blockquote><p>Each toggle takes effect <strong>immediately</strong> — no need to save.</p><hr><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Webhooks allow you to send notifications to external services when an event occurs in Nid.</p><h3 id="supported-types" tabindex="-1">Supported Types <a class="header-anchor" href="#supported-types" aria-label="Permalink to &quot;Supported Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Discord</strong></td><td>Message in a Discord channel via webhook URL</td></tr><tr><td><strong>Slack</strong></td><td>Message in a Slack channel via Incoming Webhook</td></tr><tr><td><strong>Ntfy</strong></td><td>Push notification via <a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy.sh</a></td></tr><tr><td><strong>Generic</strong></td><td>HTTP POST request to any URL</td></tr></tbody></table><h3 id="available-events" tabindex="-1">Available Events <a class="header-anchor" href="#available-events" aria-label="Permalink to &quot;Available Events&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Event</th><th>Description</th></tr></thead><tbody><tr><td><code>job.completed</code></td><td>A job completed successfully</td></tr><tr><td><code>job.failed</code></td><td>A job failed</td></tr><tr><td><code>rule.executed</code></td><td>An automatic rule was executed</td></tr><tr><td><code>quota.warning</code></td><td>Storage quota is almost reached</td></tr><tr><td><code>integrity.failed</code></td><td>Integrity check detected an issue</td></tr></tbody></table><h3 id="configure-a-webhook" tabindex="-1">Configure a Webhook <a class="header-anchor" href="#configure-a-webhook" aria-label="Permalink to &quot;Configure a Webhook&quot;">​</a></h3><ol><li>In <strong>Settings</strong> → <strong>Webhooks</strong> section</li><li>Click <strong>Add a webhook</strong></li><li>Fill in: <ul><li><strong>Name</strong>: a free-form identifier (e.g., &quot;Discord Notif&quot;)</li><li><strong>URL</strong>: the webhook URL of your service</li><li><strong>Type</strong>: Discord, Slack, Ntfy, or Generic</li><li><strong>Events</strong>: check the events that trigger the webhook</li><li><strong>Username / Password</strong> <em>(Ntfy only)</em>: credentials if the topic is protected by authentication</li></ul></li></ol><blockquote><p>📸 <em>Suggested screenshot: webhook creation form with name, URL, type, and events fields</em></p></blockquote><h3 id="test-a-webhook" tabindex="-1">Test a Webhook <a class="header-anchor" href="#test-a-webhook" aria-label="Permalink to &quot;Test a Webhook&quot;">​</a></h3><p>Click <strong>Test</strong> next to a webhook to send a test message and verify that the connection works.</p><h3 id="enable-disable" tabindex="-1">Enable / Disable <a class="header-anchor" href="#enable-disable" aria-label="Permalink to &quot;Enable / Disable&quot;">​</a></h3><p>The toggle next to each webhook allows you to enable or disable it without deleting it.</p><h3 id="security-generic-webhooks" tabindex="-1">Security (Generic Webhooks) <a class="header-anchor" href="#security-generic-webhooks" aria-label="Permalink to &quot;Security (Generic Webhooks)&quot;">​</a></h3><p><strong>Generic</strong> webhooks automatically include an <code>X-Webhook-Signature</code> header containing an HMAC-SHA256 of the payload. Your server can verify this signature to ensure the request actually comes from Nid.</p><blockquote><p>📸 <em>Suggested screenshot: list of configured webhooks with name, type, events, active/inactive toggle, and test button columns</em></p></blockquote><hr><h2 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to &quot;Usage Examples&quot;">​</a></h2><h3 id="discord" tabindex="-1">Discord <a class="header-anchor" href="#discord" aria-label="Permalink to &quot;Discord&quot;">​</a></h3><ol><li>In Discord, create a webhook in a channel: <strong>Channel Settings</strong> → <strong>Integrations</strong> → <strong>Webhooks</strong> → <strong>New Webhook</strong></li><li>Copy the webhook URL</li><li>In Nid, create a <strong>Discord</strong> type webhook with this URL</li><li>Select the events to be notified about</li></ol><h3 id="ntfy" tabindex="-1">Ntfy <a class="header-anchor" href="#ntfy" aria-label="Permalink to &quot;Ntfy&quot;">​</a></h3><p><a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy</a> allows you to receive push notifications on your phone or browser.</p><h4 id="public-topic-no-authentication" tabindex="-1">Public Topic (No Authentication) <a class="header-anchor" href="#public-topic-no-authentication" aria-label="Permalink to &quot;Public Topic (No Authentication)&quot;">​</a></h4><ol><li>Choose a topic on <a href="https://ntfy.sh" target="_blank" rel="noreferrer">ntfy.sh</a> (e.g., <code>nid-alerts</code>)</li><li>In Nid, create an <strong>Ntfy</strong> type webhook with the URL <code>https://ntfy.sh/nid-alerts</code></li><li>Install the ntfy app on your phone and subscribe to the same topic</li></ol><h4 id="protected-topic-with-login-password" tabindex="-1">Protected Topic (With Login / Password) <a class="header-anchor" href="#protected-topic-with-login-password" aria-label="Permalink to &quot;Protected Topic (With Login / Password)&quot;">​</a></h4><p>If you host your own ntfy server or use a password-protected topic:</p><ol><li>In Nid, create an <strong>Ntfy</strong> type webhook with your server&#39;s URL (e.g., <code>https://ntfy.example.com/my-topic</code>)</li><li>Enter the <strong>username</strong> and <strong>password</strong> in the fields that appear when the Ntfy type is selected</li><li>Credentials are sent via the <code>Authorization: Basic</code> HTTP header (Base64 encoding)</li><li>Click <strong>Test</strong> to verify that authentication works</li></ol><div class="tip custom-block"><p class="custom-block-title">Self-Hosted ntfy Server</p><p>If you use a self-hosted ntfy server with access control (<code>auth-default-access: deny-all</code>), you must create a user and grant them write access to the topic:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myuser</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ntfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myuser</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> write</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">Security</p><p>Ntfy credentials are stored in plain text in the database. Use a dedicated account with minimal permissions (write-only on the relevant topic).</p></div>`,48)])])}const b=e(n,[["render",s]]);export{u as __pageData,b as default};
